import React, { useState, useEffect } from "react";
import { Field, Form } from "react-final-form";
import { InputField } from "../../../common/InputText";
import { Error, PageMode, required } from "../../../common/Utilitis";
import CityService from "../../services/cities.service";
import CountryService from "../../services/countries.service";
import { useTranslation } from "react-i18next";

function AddUpdateForm(props) {
  const [t, i18next] = useTranslation();
  const { mode, selectedCity, onClose } = props;
  const [isLoading, setIsLoading] = useState(false);
  const [isCountryLoading, setIsCountryLoading] = useState(false);
  const [message, setMessage] = useState();
  const [countriesData, setCountriesData] = useState();
  const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

  useEffect(async () => {
    setIsCountryLoading(true);
    const response = await CountryService.getAllCountries();
    setMessage(!!response?.message && response?.message);
    if (response.success) {
      setCountriesData(response.body);
    }
    setIsCountryLoading(false);
  }, []);

  const onSubmit = async (values) => {
    console.log(`onSubmit :: ${JSON.stringify(values, 0, 2)}`);
    setIsLoading(true);
    let response;
    if (mode === PageMode.Update) {
      response = await CityService.updateCity(selectedCity?.id, values);
    } else {
      response = await CityService.createCity(values);
    }
    setIsLoading(false);
    if (!!!response.success && !response.success) {
      setMessage(!!response.message && response.message);
      return;
    }
    onClose(response.body);
  };

  const validate = async (values) => {
    const errors = {};
    if (!values.name) {
      errors.name = required;
    }
    if (!values.country) {
      errors.country = required;
    }
    return errors;
  };

  let form = (
    <Form
      validate={validate}
      onSubmit={onSubmit}
      initialValues={{
        name: selectedCity?.name,
        country: selectedCity?.countryId,
      }}
      render={({
        handleSubmit,
        onChange,
        submitError,
        form,
        submitting,
        pristine,
        values,
      }) => (
        <form onSubmit={handleSubmit} className="needs-validation" noValidate>
          {message && (
            <div className="invalid-feedback d-block mb-2">{message}</div>
          )}
          <div className="row form-row">
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t("City.Country")}</label>
                <Field name="country" showerrorbeside="true">
                  {({ input, meta }) => {
                    return (
                      <select
                        className="form-control select"
                        {...input.select}
                        defaultValue={values.country}
                        value={values.country}
                        onChange={(e) => {
                          input.onChange(e);
                        }}
                      >
                        <option value="">
                          {isCountryLoading === true
                            ? t("loading")
                            : t("City.SelectCountry")}
                        </option>
                        {countriesData?.map((val, index) => (
                          <option key={index} value={val.id}>
                            {val.name}
                          </option>
                        ))}
                      </select>
                    );
                  }}
                </Field>
                <Error name={"country"} showerrorbeside="true" />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t("City.Name")}</label>
                <Field
                  name="name"
                  className="form-control floating"
                  type="text"
                  component={InputField}
                />
              </div>
            </div>
          </div>
          <div className="submit-section">
            <button
              type="submit"
              className="btn btn-primary submit-btn"
              disabled={isLoading}
            >
              {!isLoading ? t(`City.Save`) : ""}
              {isLoading && (
                <span className="spinner-border spinner-border-sm mb-1"></span>
              )}
            </button>
            <button
              className="btn btn-secondary submit-btn"
              onClick={(e) => {
                e.preventDefault();
                onClose(null);
              }}
            >
              {t("City.Close")}
            </button>
          </div>
        </form>
      )}
    />
  );

  return <div>{form}</div>;
}
export default AddUpdateForm;
